export interface User {
  id: string;
  name: string;
  email: string;
  createdAt: Date;
}

export function createUser(data: Omit<User, 'id' | 'createdAt'>): User {
  return {
    ...data,
    id: crypto.randomUUID(),
    createdAt: new Date()
  };
}

import { User, createUser } from './model';

const users: Map<string, User> = new Map();

export async function getUserById(id: string): Promise<User | null> {
  return users.get(id) || null;
}

export async function createUserService(data: Omit<User, 'id' | 'createdAt'>): Promise<User> {
  const user = createUser(data);
  users.set(user.id, user);
  return user;
}

export async function listUsers(): Promise<User[]> {
  return Array.from(users.values());
}

import { Router } from 'express';
import { getUserById, createUserService, listUsers } from './service';

export const usersRouter = Router();

usersRouter.get('/users', async (req, res) => {
  const users = await listUsers();
  res.json(users);
});

usersRouter.get('/users/:id', async (req, res) => {
  const user = await getUserById(req.params.id);
  if (!user) return res.status(404).json({ error: 'User not found' });
  res.json(user);
});

usersRouter.post('/users', async (req, res) => {
  const user = await createUserService(req.body);
  res.status(201).json(user);
});

export * from './model';
export * from './service';
export { usersRouter } from './routes';
